(1, 'everydayjobsannouncement/3237', 'publer_69a53106ecd1e8f04decd9e0', '6a4ab1558df7ca189328002c', 'рҹҡҖ Digital Marketing Officer Wanted! \n\nAre you ready to drive your career forward in the vibrant world of digital marketing? Join us in the automotive industry, where your creativity meets innovation!\n\nвң… Develop and execute digital marketing strategies to boost brand presence.\nрҹ“Ң Manage social media platforms to engage and grow our audience.\nвң… Collaborate with the team to create compelling content.\nрҹ“Ң Analyze campaign data to optimize performance and ROI.\n\nрҹҺҜ Strong understanding of digital marketing tools and platforms.\nвң”пёҸ Excellent communication and creative skills.\nрҹҺҜ Experience in managing social media channels.\nвң”пёҸ Ability to work in a fast-paced environment.\n\nрҹ”— Apply your CV to:\nTelegram: @seekfitjob\nEmail: hr@seekfitjob.com\nвҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”\nTG Channel: t.me/SeekFitJobKH\nMore jobs: www.seekfitjob.com\n\n#JobAlert #SeekFitJob #Cambodia #DigitalMarketing #PhnomPenh', 'attached', '2026-07-05 19:32:37'),
(2, 'cdlhrjobs/8034', 'publer_69a53148df17f30e771bf6fa', '6a4b55da0e767ee3e397b3f3', 'рҹҡҖ Air Freight Forwarding (AFF) Manager Wanted!\n\nSeekFitJob is looking for motivated candidates for the Air Freight Forwarding (AFF) Manager position. This is a good opportunity for professionals who are ready to grow, contribute, and move forward.\n\nKey Responsibilities\nвң… Coordinate daily logistics, shipment, import/export, or warehouse operations\nвң… Prepare and follow up on operational documents and delivery timelines\nвң… Work with customers, vendors, agents, and internal teams\nвң… Monitor inventory, shipment status, and service quality\nвң… Support smooth and efficient end-to-end operations\n\nRequirements / Qualifications\nрҹҺҜ Relevant experience or interest in logistics, warehouse, freight, or supply chain\nрҹҺҜ Good coordination, problem-solving, and communication skills\nрҹҺҜ Able to manage documents, timelines, and operational follow-up\nрҹҺҜ Detail-oriented and able to work under pressure\nрҹҺҜ Responsible, flexible, and team-oriented\n\nWhat We Offer\nрҹ’ј Career opportunity with growth potential\nрҹ“Ҳ Opportunity to develop professional skills and experience\nрҹӨқ Supportive working environment for motivated candidates\n\nрҹ”— Apply your CV to:\nTelegram: @seekfitjob\nEmail: hr@seekfitjob.com\nвҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”\nTG Channel: t.me/SeekFitJobKH\nMore jobs: www.seekfitjob.com\n\n#SeekFitJob #LogisticsJobs #SupplyChainJobs #HiringCambodia', 'attached', '2026-07-06 07:14:34'),
(3, 'cdlhrjobs/8034', 'publer_69a53106ecd1e8f04decd9e0', '6a4b55da0e767ee3e397b3f3', 'рҹҡҖ Air Freight Forwarding (AFF) Manager Wanted!\n\nSeekFitJob is looking for motivated candidates for the Air Freight Forwarding (AFF) Manager position. This is a good opportunity for professionals who are ready to grow, contribute, and move forward.\n\nKey Responsibilities\nвң… Coordinate daily logistics, shipment, import/export, or warehouse operations\nвң… Prepare and follow up on operational documents and delivery timelines\nвң… Work with customers, vendors, agents, and internal teams\nвң… Monitor inventory, shipment status, and service quality\nвң… Support smooth and efficient end-to-end operations\n\nRequirements / Qualifications\nрҹҺҜ Relevant experience or interest in logistics, warehouse, freight, or supply chain\nрҹҺҜ Good coordination, problem-solving, and communication skills\nрҹҺҜ Able to manage documents, timelines, and operational follow-up\nрҹҺҜ Detail-oriented and able to work under pressure\nрҹҺҜ Responsible, flexible, and team-oriented\n\nWhat We Offer\nрҹ’ј Career opportunity with growth potential\nрҹ“Ҳ Opportunity to develop professional skills and experience\nрҹӨқ Supportive working environment for motivated candidates\n\nрҹ”— Apply your CV to:\nTelegram: @seekfitjob\nEmail: hr@seekfitjob.com\nвҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”\nTG Channel: t.me/SeekFitJobKH\nMore jobs: www.seekfitjob.com\n\n#SeekFitJob #LogisticsJobs #SupplyChainJobs #HiringCambodia', 'attached', '2026-07-06 07:14:34'),
